	private PlanningCandidate chooseCandidate(List<StatementPattern> patterns, Set<String> configuredIndexes,
			List<String> visibleVariables) {
		List<String> indexes = configuredIndexes.stream().sorted().toList();
		if (visibleVariables.size() <= 8) {
			List<String> current = new ArrayList<>(visibleVariables.size());
			List<String> remaining = new ArrayList<>(visibleVariables);
			return permute(patterns, indexes, current, remaining, null);
		}

		List<String> greedyOrder = greedyVariableOrder(patterns, visibleVariables);
		return evaluateCandidate(patterns, indexes, greedyOrder);
	}

	private PlanningCandidate permute(List<StatementPattern> patterns, List<String> indexes, List<String> current,
			List<String> remaining, PlanningCandidate best) {
		if (remaining.isEmpty()) {
			PlanningCandidate candidate = evaluateCandidate(patterns, indexes, current);
			return pickBetter(best, candidate);
		}

		for (int i = 0; i < remaining.size(); i++) {
			String next = remaining.remove(i);
			current.add(next);
			best = permute(patterns, indexes, current, remaining, best);
			current.remove(current.size() - 1);
			remaining.add(i, next);
		}
		return best;
	}

	private List<String> greedyVariableOrder(List<StatementPattern> patterns, List<String> visibleVariables) {
		Map<String, Long> occurrences = visibleVariables.stream()
				.collect(java.util.stream.Collectors.toMap(name -> name, name -> patterns.stream()
						.filter(pattern -> pattern.getVarList()
								.stream()
								.anyMatch(var -> var != null && !var.hasValue() && !var.isAnonymous()
										&& name.equals(var.getName())))
						.count()));
		List<String> ordered = new ArrayList<>(visibleVariables);
		ordered.sort(Comparator.<String, Long>comparing(occurrences::get)
				.reversed()
				.thenComparing(Comparator.naturalOrder()));
		return ordered;
	}

	private PlanningCandidate evaluateCandidate(List<StatementPattern> patterns, List<String> indexes,
			List<String> variableOrder) {
		List<String> indexNames = new ArrayList<>(patterns.size());
		int score = 0;
		for (StatementPattern pattern : patterns) {
			IndexChoice choice = chooseIndex(pattern, indexes, variableOrder);
			if (choice == null) {
				return null;
			}
			indexNames.add(choice.indexName);
			score += choice.score;
		}
		return new PlanningCandidate(List.copyOf(variableOrder), List.copyOf(indexNames), score);
	}

	private PlanningCandidate pickBetter(PlanningCandidate left, PlanningCandidate right) {
		if (left == null) {
			return right;
		}
		if (right == null) {
			return left;
		}
		if (right.score != left.score) {
			return right.score > left.score ? right : left;
		}
		int orderCompare = compareLists(right.variableOrder, left.variableOrder);
		if (orderCompare != 0) {
			return orderCompare < 0 ? right : left;
		}
		int indexCompare = compareLists(right.indexNames, left.indexNames);
		return indexCompare < 0 ? right : left;
	}

	private int compareLists(List<String> left, List<String> right) {
		int sizeCompare = Integer.compare(left.size(), right.size());
		if (sizeCompare != 0) {
			return sizeCompare;
		}
		for (int i = 0; i < left.size(); i++) {
			int compare = left.get(i).compareTo(right.get(i));
			if (compare != 0) {
				return compare;
			}
		}
		return 0;
	}

	private IndexChoice chooseIndex(StatementPattern pattern, List<String> indexes, List<String> variableOrder) {
		IndexChoice best = null;
		for (String indexName : indexes) {
			IndexChoice candidate = compatible(pattern, indexName, variableOrder);
			if (candidate == null) {
				continue;
			}
			if (best == null || candidate.score > best.score
					|| (candidate.score == best.score && candidate.indexName.compareTo(best.indexName) < 0)) {
				best = candidate;
			}
		}
		return best;
	}

	private IndexChoice compatible(StatementPattern pattern, String indexName, List<String> variableOrder) {
		int lastRank = -1;
		boolean hiddenSeen = false;
		int score = 0;
		for (int i = 0; i < indexName.length(); i++) {
			LmdbLftjPatternPlan.TermRef term = term(pattern, indexName.charAt(i));
			if (term.isConstant()) {
				score += 8 - i;
				continue;
			}
			if (term.isHidden()) {
				hiddenSeen = true;
				continue;
			}
			if (hiddenSeen) {
				return null;
			}
			int rank = variableOrder.indexOf(term.name());
			if (rank < lastRank) {
				return null;
			}
			lastRank = rank;
			score += Math.max(1, variableOrder.size() - rank);
		}
		return new IndexChoice(indexName, score);
	}

	private LmdbLftjPatternPlan.TermRef term(StatementPattern pattern, char field) {
		switch (field) {
		case 's':
			return LmdbLftjPatternPlan.TermRef.of(TripleStore.SUBJ_IDX, pattern.getSubjectVar());
		case 'p':
			return LmdbLftjPatternPlan.TermRef.of(TripleStore.PRED_IDX, pattern.getPredicateVar());
		case 'o':
			return LmdbLftjPatternPlan.TermRef.of(TripleStore.OBJ_IDX, pattern.getObjectVar());
		case 'c':
			return LmdbLftjPatternPlan.TermRef.of(TripleStore.CONTEXT_IDX, pattern.getContextVar());
		default:
			throw new IllegalArgumentException("Unknown LMDB field: " + field);
		}
	}

